svg.script:
(function() {
  var svg = document.getElementById('root');

  /* ── Dark mode toggle ── */
  var isDark = false;

  var boxes = [
    { id:1, color:'#00D4E8', darkColor:'#22D3EE' },
    { id:2, color:'#00B87A', darkColor:'#10B981' },
    { id:3, color:'#F59E0B', darkColor:'#FBB724' },
    { id:4, color:'#F43F5E', darkColor:'#FB6181' },
    { id:5, color:'#8B5CF6', darkColor:'#A78BFA' },
    { id:6, color:'#3B82F6', darkColor:'#60A5FA' },
    { id:7, color:'#0D9488', darkColor:'#2DD4BF' },
    { id:8, color:'#64748B', darkColor:'#94A3B8' },
  ];

  function swapColors(dark) {
    boxes.forEach(function(b) {
      var box = document.getElementById('boxr' + b.id);
      var med = document.getElementById('med' + b.id);
      var out = document.getElementById('out' + b.id);
      var wc  = dark ? b.darkColor : b.color;
      if (box) box.setAttribute('fill', wc);
      if (out) out.setAttribute('stroke', wc);
      // whiskers — find by traversing; simpler: set via color matching
      var bw = document.getElementById('bw' + b.id);
      if (bw) {
        var lines = bw.querySelectorAll('line.whisker');
        lines.forEach(function(l) { l.setAttribute('stroke', wc); });
      }
    });
  }

  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
    swapColors(wantDark);
  }

  document.getElementById('dark-toggle').addEventListener('click', function() {
    setMode(!isDark);
  });

  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });

  (function() {
    var href = window.location.href;
    setMode(href.indexOf('theme=dark') !== -1);
  })();
})();
